--
-- Table structure for table `pokemon_entrenador`
--

DROP TABLE IF EXISTS `pokemon_entrenador`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pokemon_entrenador` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `id_entrenador` int unsigned NOT NULL,
  `id_pokemon` int unsigned NOT NULL,
  `nivel_captura` int DEFAULT '1',
  `apodo` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `en_equipo` tinyint(1) DEFAULT '1',
  `fecha_captura` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `id_entrenador` (`id_entrenador`),
  KEY `id_pokemon` (`id_pokemon`),
  CONSTRAINT `pokemon_entrenador_ibfk_1` FOREIGN KEY (`id_entrenador`) REFERENCES `entrenadores` (`id`) ON DELETE CASCADE,
  CONSTRAINT `pokemon_entrenador_ibfk_2` FOREIGN KEY (`id_pokemon`) REFERENCES `pokemon` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

